import { useState, useEffect, useRef } from 'react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Send, X, MessageCircle, Loader2 } from 'lucide-react';

/**
 * ChatWindow — real-time chat between customer and provider for a booking.
 * Props:
 *   providerId    — provider's record id
 *   customerEmail — customer's email
 *   currentUserEmail — logged-in user's email
 *   currentUserRole  — 'customer' | 'provider'
 *   providerName     — display name
 *   onClose          — optional close handler
 */
export default function ChatWindow({ providerId, customerEmail, currentUserEmail, currentUserRole, providerName, onClose }) {
    const [messages, setMessages] = useState([]);
    const [text, setText] = useState('');
    const [loading, setLoading] = useState(true);
    const [sending, setSending] = useState(false);
    const bottomRef = useRef(null);

    useEffect(() => {
        if (!providerId || !customerEmail) return;
        setLoading(true);
            .then(msgs => { setMessages(msgs); setLoading(false); });

        // Subscribe to real-time updates
            if (event.type === 'create' && event.data.provider_id === providerId && event.data.customer_email === customerEmail) {
                setMessages(prev => {
                    if (prev.find(m => m.id === event.id)) return prev;
                    return [...prev, event.data];
                });
            }
        });
        return unsub;
    }, [providerId, customerEmail]);

    useEffect(() => {
        bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
    }, [messages]);

    const send = async () => {
        const trimmed = text.trim();
        if (!trimmed || sending) return;
        setSending(true);
        setText('');
            provider_id: providerId,
            customer_email: customerEmail,
            sender_email: currentUserEmail,
            sender_role: currentUserRole,
            text: trimmed,
            is_read: false,
        });
        setSending(false);
    };

    const handleKey = (e) => {
        if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); send(); }
    };

    return (
        <div className="flex flex-col h-full bg-background border border-border rounded-2xl overflow-hidden shadow-float">
            {/* Header */}
            <div className="flex items-center justify-between px-4 py-3 border-b border-border bg-card shrink-0">
                <div className="flex items-center gap-2">
                    <div className="h-8 w-8 rounded-full bg-zinc-900 dark:bg-zinc-100 flex items-center justify-center">
                        <MessageCircle className="h-4 w-4 text-white dark:text-zinc-900" />
                    </div>
                    <div>
                        <p className="text-sm font-semibold">{currentUserRole === 'customer' ? providerName || 'Provider' : customerEmail}</p>
                        <p className="text-xs text-muted-foreground">Chat</p>
                    </div>
                </div>
                {onClose && (
                    <button onClick={onClose} className="h-7 w-7 rounded-lg flex items-center justify-center hover:bg-zinc-100 dark:hover:bg-zinc-800 transition-colors text-muted-foreground">
                        <X className="h-4 w-4" />
                    </button>
                )}
            </div>

            {/* Messages */}
            <div className="flex-1 overflow-y-auto p-4 space-y-3 min-h-0">
                {loading ? (
                    <div className="flex justify-center py-8"><Loader2 className="h-5 w-5 animate-spin text-muted-foreground" /></div>
                ) : messages.length === 0 ? (
                    <p className="text-center text-sm text-muted-foreground py-8">No messages yet. Say hello!</p>
                ) : (
                    messages.map(msg => {
                        const isMe = msg.sender_email === currentUserEmail;
                        return (
                            <div key={msg.id} className={`flex ${isMe ? 'justify-end' : 'justify-start'}`}>
                                <div className={`max-w-[80%] px-3.5 py-2.5 rounded-2xl text-sm leading-relaxed ${isMe
                                        ? 'bg-zinc-900 dark:bg-zinc-100 text-white dark:text-zinc-900 rounded-br-sm'
                                        : 'bg-zinc-100 dark:bg-zinc-800 text-zinc-900 dark:text-zinc-100 rounded-bl-sm'
                                    }`}>
                                    {msg.text}
                                    <div className={`text-[10px] mt-1 ${isMe ? 'text-white/50 dark:text-zinc-500' : 'text-muted-foreground'}`}>
                                        {new Date(msg.created_date).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                                    </div>
                                </div>
                            </div>
                        );
                    })
                )}
                <div ref={bottomRef} />
            </div>

            {/* Input */}
            <div className="px-4 py-3 border-t border-border bg-card shrink-0">
                <div className="flex gap-2">
                    <Input
                        value={text}
                        onChange={e => setText(e.target.value)}
                        onKeyDown={handleKey}
                        placeholder="Type a message..."
                        className="rounded-xl flex-1 text-sm"
                        disabled={sending}
                    />
                    <Button onClick={send} disabled={!text.trim() || sending} className="h-9 w-9 rounded-xl p-0 bg-zinc-900 dark:bg-zinc-100 hover:bg-zinc-800 dark:hover:bg-zinc-200 text-white dark:text-zinc-900 shrink-0">
                        {sending ? <Loader2 className="h-4 w-4 animate-spin" /> : <Send className="h-4 w-4" />}
                    </Button>
                </div>
            </div>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { Calendar, MapPin, Ticket, ArrowRight, Users, Plus } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { Input } from '@/components/ui/input';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { toast } from 'sonner';

const CATEGORY_ICONS = { concert: '🎵', workshop: '🛠️', meetup: '🤝', sports: '⚽', festival: '🎉', exhibition: '🖼️', food: '🍽️', other: '📅' };
const VENUE_TYPES = { hall: 'Community Hall', rooftop: 'Rooftop', open_ground: 'Open Ground', indoor: 'Indoor', online: 'Online', other: 'Other' };

export default function EventsSection({ user }) {
    const [events, setEvents] = useState([]);
    const [loading, setLoading] = useState(true);
    const [ticketDialog, setTicketDialog] = useState(null);
    const [buying, setBuying] = useState(false);
    const [quickCreate, setQuickCreate] = useState(false);
    const [form, setForm] = useState({ title: '', category: 'meetup', venue_name: '', date: '', ticket_price: 0, is_free: true, total_tickets: 100 });
    const [saving, setSaving] = useState(false);

    useEffect(() => {
            .then(e => { setEvents(e); setLoading(false); });
    }, []);

    const buyTicket = async (event) => {
        if (!user) { toast.error('Please log in to buy tickets'); return; }
        setBuying(true);
        const code = `TRV-${Math.random().toString(36).substring(2, 8).toUpperCase()}`;
            event_id: event.id, event_title: event.title,
            buyer_email: user.email, buyer_name: user.full_name || user.email,
            quantity: 1, unit_price: event.ticket_price || 0,
            total_amount: event.ticket_price || 0,
            status: 'active', ticket_code: code,
        });
        setEvents(prev => prev.map(e => e.id === event.id ? { ...e, tickets_sold: (e.tickets_sold || 0) + 1 } : e));
        toast.success(`Ticket booked! Code: ${code}`);
        setBuying(false);
        setTicketDialog(null);
    };

    const createEvent = async () => {
        if (!form.title || !form.date || !form.venue_name) { toast.error('Title, date and venue required'); return; }
        setSaving(true);
        toast.success('Event published!');
        setSaving(false);
        setQuickCreate(false);
    };

    return (
        <section>
            <div className="flex items-center justify-between mb-5">
                <div>
                    <h2 className="font-display font-bold text-xl tracking-tight">Local Events</h2>
                    <p className="text-zinc-500 text-sm mt-0.5 font-inter">Concerts, workshops, meetups & ticketed experiences</p>
                </div>
                <div className="flex items-center gap-2">
                    {user && (
                        <Button size="sm" variant="outline" className="rounded-xl gap-1.5 h-8 text-xs" onClick={() => setQuickCreate(true)}>
                            <Plus className="h-3.5 w-3.5" /> Create Event
                        </Button>
                    )}
                    <Link to="/events" className="flex items-center gap-1.5 text-sm font-medium text-zinc-400 hover:text-zinc-900 dark:hover:text-zinc-100 transition-colors">
                        All events <ArrowRight className="h-3.5 w-3.5" />
                    </Link>
                </div>
            </div>

            {/* Category quick-filters */}
            <div className="flex gap-2 flex-wrap mb-4">
                {[['🎵', 'Concerts', '/events?cat=concert'], ['🛠️', 'Workshops', '/events?cat=workshop'], ['🤝', 'Meetups', '/events?cat=meetup'], ['🎉', 'Festivals', '/events?cat=festival'], ['🍽️', 'Food', '/events?cat=food']].map(([icon, label, to]) => (
                    <Link key={to} to={to} className="flex items-center gap-1.5 h-8 px-3 rounded-xl bg-zinc-100 dark:bg-zinc-800 text-xs font-semibold text-zinc-600 dark:text-zinc-300 hover:bg-zinc-900 hover:text-white dark:hover:bg-zinc-100 dark:hover:text-zinc-900 transition-all">
                        {icon} {label}
                    </Link>
                ))}
            </div>

            {loading ? (
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                    {Array.from({ length: 3 }).map((_, i) => <div key={i} className="skeleton-wave h-52 rounded-2xl" />)}
                </div>
            ) : events.length === 0 ? (
                <div className="card-premium p-10 text-center">
                    <Calendar className="h-8 w-8 mx-auto mb-3 text-zinc-200" />
                    <p className="text-zinc-400 text-sm">No upcoming events yet</p>
                    {user && <Button size="sm" variant="outline" className="rounded-xl mt-3" onClick={() => setQuickCreate(true)}>Create the first event</Button>}
                </div>
            ) : (
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                    {events.map(event => {
                        const soldOut = (event.tickets_sold || 0) >= (event.total_tickets || 1);
                        const pct = Math.min(100, Math.round((event.tickets_sold || 0) / (event.total_tickets || 1) * 100));
                        return (
                            <div key={event.id} className="card-premium overflow-hidden group hover:-translate-y-0.5 transition-transform">
                                <div className="h-32 bg-gradient-to-br from-zinc-800 to-zinc-600 flex items-center justify-center text-5xl relative">
                                    {event.image_url
                                        ? <img src={event.image_url} alt="" className="absolute inset-0 w-full h-full object-cover" />
                                        : <span>{CATEGORY_ICONS[event.category] || '📅'}</span>
                                    }
                                    <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent" />
                                    <span className="absolute top-2.5 left-2.5 bg-white/90 dark:bg-zinc-900/90 text-[10px] font-bold px-2 py-0.5 rounded-full capitalize">{event.category}</span>
                                    {soldOut && <span className="absolute top-2.5 right-2.5 bg-red-500 text-white text-[10px] font-bold px-2 py-0.5 rounded-full">SOLD OUT</span>}
                                    <p className="absolute bottom-2.5 left-3 text-white font-bold text-sm line-clamp-1 drop-shadow">{event.title}</p>
                                </div>
                                <div className="p-4">
                                    <div className="space-y-1 text-xs text-zinc-500 mb-3">
                                        <div className="flex items-center gap-1.5"><Calendar className="h-3.5 w-3.5 shrink-0" />{event.date}{event.start_time && ` · ${event.start_time}`}</div>
                                        <div className="flex items-center gap-1.5"><MapPin className="h-3.5 w-3.5 shrink-0" />{event.venue_name} · {VENUE_TYPES[event.venue_type] || event.venue_type}</div>
                                        <div className="flex items-center gap-1.5"><Users className="h-3.5 w-3.5 shrink-0" />{event.tickets_sold || 0}/{event.total_tickets} going</div>
                                    </div>
                                    <div className="h-1 bg-zinc-100 dark:bg-zinc-800 rounded-full mb-3 overflow-hidden">
                                        <div className="h-full bg-zinc-900 dark:bg-zinc-100 rounded-full" style={{ width: `${pct}%` }} />
                                    </div>
                                    {event.bundle_services?.length > 0 && (
                                        <div className="flex gap-1 flex-wrap mb-2">
                                            {event.bundle_services.slice(0, 3).map(s => <span key={s} className="text-[10px] bg-emerald-50 dark:bg-emerald-900/20 text-emerald-700 dark:text-emerald-400 px-1.5 py-0.5 rounded-full">{s}</span>)}
                                        </div>
                                    )}
                                    <div className="flex items-center justify-between mt-1">
                                        <span className="font-bold text-sm">{event.is_free || !event.ticket_price ? '🆓 Free' : `$${event.ticket_price}`}</span>
                                        <Button size="sm" className="rounded-xl h-7 text-xs gap-1" disabled={soldOut} onClick={() => setTicketDialog(event)}>
                                            <Ticket className="h-3 w-3" /> {soldOut ? 'Full' : 'Get Ticket'}
                                        </Button>
                                    </div>
                                </div>
                            </div>
                        );
                    })}
                </div>
            )}

            {/* Venue spotlight strip */}
            <div className="mt-4 grid grid-cols-3 md:grid-cols-6 gap-2">
                {[['🏛️', 'Grand Hall'], ['🌆', 'Rooftop'], ['🌿', 'Open Ground'], ['🏢', 'The Loft'], ['🌅', 'Terrace'], ['✨', 'Ballroom']].map(([emoji, name]) => (
                    <Link key={name} to="/events?tab=venues"
                        className="glass rounded-xl p-2.5 text-center hover:shadow-premium transition-all group">
                        <div className="text-2xl mb-1">{emoji}</div>
                        <p className="text-[10px] font-semibold text-zinc-600 dark:text-zinc-400 group-hover:text-zinc-900 dark:group-hover:text-zinc-100">{name}</p>
                    </Link>
                ))}
            </div>

            {/* Ticket Dialog */}
            <Dialog open={!!ticketDialog} onOpenChange={() => setTicketDialog(null)}>
                {ticketDialog && (
                    <DialogContent className="max-w-sm">
                        <DialogHeader><DialogTitle>Get Ticket</DialogTitle></DialogHeader>
                        <div className="space-y-4 pt-1">
                            <div className="bg-zinc-50 dark:bg-zinc-900 rounded-2xl p-4">
                                <p className="font-bold">{ticketDialog.title}</p>
                                <p className="text-xs text-zinc-400 mt-1">{ticketDialog.date} · {ticketDialog.venue_name}</p>
                            </div>
                            <div className="flex items-center justify-between">
                                <p className="text-sm font-semibold">Price</p>
                                <p className="font-bold text-xl">{ticketDialog.is_free || !ticketDialog.ticket_price ? 'Free' : `$${ticketDialog.ticket_price}`}</p>
                            </div>
                            <div className="flex items-center justify-between text-xs text-zinc-400">
                                <span>Remaining</span>
                                <span className="font-semibold">{(ticketDialog.total_tickets || 0) - (ticketDialog.tickets_sold || 0)} tickets</span>
                            </div>
                            {ticketDialog.bundle_services?.length > 0 && (
                                <div>
                                    <p className="text-xs font-bold text-zinc-400 uppercase tracking-wider mb-2">Included Services</p>
                                    <div className="flex flex-wrap gap-1.5">
                                        {ticketDialog.bundle_services.map(s => <span key={s} className="text-xs bg-emerald-50 dark:bg-emerald-900/20 text-emerald-700 px-2 py-0.5 rounded-full">{s}</span>)}
                                    </div>
                                </div>
                            )}
                            <Button className="w-full h-11 rounded-xl gap-2" onClick={() => buyTicket(ticketDialog)} disabled={buying}>
                                <Ticket className="h-4 w-4" /> {buying ? 'Booking…' : ticketDialog.is_free || !ticketDialog.ticket_price ? 'Reserve Free Ticket' : `Pay $${ticketDialog.ticket_price}`}
                            </Button>
                        </div>
                    </DialogContent>
                )}
            </Dialog>

            {/* Quick Create Dialog */}
            <Dialog open={quickCreate} onOpenChange={setQuickCreate}>
                <DialogContent className="max-w-md">
                    <DialogHeader><DialogTitle>Create Event</DialogTitle></DialogHeader>
                    <div className="space-y-3 pt-1">
                        <Input placeholder="Event title *" value={form.title} onChange={e => setForm(p => ({ ...p, title: e.target.value }))} className="rounded-xl" />
                        <div className="grid grid-cols-2 gap-3">
                            <Select value={form.category} onValueChange={v => setForm(p => ({ ...p, category: v }))}>
                                <SelectTrigger className="rounded-xl"><SelectValue /></SelectTrigger>
                                <SelectContent>{Object.entries(CATEGORY_ICONS).map(([k, v]) => <SelectItem key={k} value={k}>{v} {k}</SelectItem>)}</SelectContent>
                            </Select>
                            <Input type="date" value={form.date} onChange={e => setForm(p => ({ ...p, date: e.target.value }))} className="rounded-xl" />
                        </div>
                        <Input placeholder="Venue name *" value={form.venue_name} onChange={e => setForm(p => ({ ...p, venue_name: e.target.value }))} className="rounded-xl" />
                        <div className="grid grid-cols-2 gap-3">
                            <Input type="number" placeholder="Total tickets" value={form.total_tickets} onChange={e => setForm(p => ({ ...p, total_tickets: Number(e.target.value) }))} className="rounded-xl" />
                            <Input type="number" placeholder="Price (0 = free)" value={form.ticket_price} onChange={e => setForm(p => ({ ...p, ticket_price: Number(e.target.value), is_free: Number(e.target.value) === 0 }))} className="rounded-xl" />
                        </div>
                        <div className="flex gap-2 pt-1">
                            <Button className="flex-1 h-10 rounded-xl" onClick={createEvent} disabled={saving}>{saving ? 'Publishing…' : 'Publish Event'}</Button>
                            <Link to="/events" className="flex-1">
                                <Button variant="outline" className="w-full h-10 rounded-xl">Full Editor</Button>
                            </Link>
                        </div>
                    </div>
                </DialogContent>
            </Dialog>
        </section>
    );
}

import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { Car, Package, Truck, Key, MapPin, Clock, ArrowRight, Plus, Users } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { Input } from '@/components/ui/input';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { toast } from 'sonner';

const TYPE_CONFIG = {
    carpool: { icon: Car, label: 'Carpool', color: 'bg-blue-100 text-blue-700', light: 'bg-blue-50 dark:bg-blue-950/30' },
    delivery: { icon: Package, label: 'Delivery', color: 'bg-amber-100 text-amber-700', light: 'bg-amber-50 dark:bg-amber-950/30' },
    moving: { icon: Truck, label: 'Moving', color: 'bg-emerald-100 text-emerald-700', light: 'bg-emerald-50 dark:bg-emerald-950/30' },
    car_rental: { icon: Key, label: 'Car Rental', color: 'bg-violet-100 text-violet-700', light: 'bg-violet-50 dark:bg-violet-950/30' },
};

export default function TransportSection({ user }) {
    const [rides, setRides] = useState([]);
    const [loading, setLoading] = useState(true);
    const [activeType, setActiveType] = useState('all');
    const [postDialog, setPostDialog] = useState(false);
    const [requestDialog, setRequestDialog] = useState(null);
    const [form, setForm] = useState({ type: 'carpool', from_location: '', to_location: '', date: '', departure_time: '', seats_available: 3, price_per_seat: 0, vehicle: '', contact_phone: '' });
    const [saving, setSaving] = useState(false);

    useEffect(() => {
            .then(r => { setRides(r); setLoading(false); });
    }, []);

    const filtered = activeType === 'all' ? rides : rides.filter(r => r.type === activeType);

    const post = async () => {
        if (!form.from_location || !form.to_location || !form.date) { toast.error('From, to and date required'); return; }
        setSaving(true);
        toast.success('Listing posted!');
        setSaving(false);
        setPostDialog(false);
    };

    const requestSeat = async (ride) => {
        if (!user) { toast.error('Please log in'); return; }
        setRides(prev => prev.map(r => r.id === ride.id ? { ...r, seats_taken: (r.seats_taken || 0) + 1 } : r));
        toast.success('Request sent! Contact the driver to confirm.');
        setRequestDialog(null);
    };

    // Stats
    const counts = { all: rides.length, carpool: 0, delivery: 0, moving: 0, car_rental: 0 };
    rides.forEach(r => { if (counts[r.type] !== undefined) counts[r.type]++; });

    return (
        <section>
            <div className="flex items-center justify-between mb-5">
                <div>
                    <h2 className="font-display font-bold text-xl tracking-tight">Transport Hub</h2>
                    <p className="text-zinc-500 text-sm mt-0.5 font-inter">Carpools, delivery, moving & car rentals nearby</p>
                </div>
                <div className="flex items-center gap-2">
                    {user && (
                        <Button size="sm" variant="outline" className="rounded-xl gap-1.5 h-8 text-xs" onClick={() => setPostDialog(true)}>
                            <Plus className="h-3.5 w-3.5" /> Post Listing
                        </Button>
                    )}
                    <Link to="/transport" className="flex items-center gap-1.5 text-sm font-medium text-zinc-400 hover:text-zinc-900 dark:hover:text-zinc-100 transition-colors">
                        All listings <ArrowRight className="h-3.5 w-3.5" />
                    </Link>
                </div>
            </div>

            {/* Type tabs with counts */}
            <div className="grid grid-cols-5 gap-2 mb-4">
                {[['all', 'All', null], ...Object.entries(TYPE_CONFIG).map(([k, v]) => [k, v.label, v.icon])].map(([key, label, Icon]) => (
                    <button key={key} onClick={() => setActiveType(key)}
                        className={`rounded-xl p-2.5 text-center border-2 transition-all ${activeType === key ? 'border-zinc-900 dark:border-zinc-100 bg-zinc-900 dark:bg-zinc-100 text-white dark:text-zinc-900' : 'border-transparent bg-zinc-100 dark:bg-zinc-800 text-zinc-600 dark:text-zinc-400 hover:border-zinc-300'}`}>
                        {Icon && <Icon className="h-4 w-4 mx-auto mb-0.5" />}
                        <p className="text-[10px] font-bold">{label}</p>
                        <p className="text-[10px] opacity-60">{counts[key] || 0}</p>
                    </button>
                ))}
            </div>

            {loading ? (
                <div className="space-y-3">{Array.from({ length: 3 }).map((_, i) => <div key={i} className="skeleton-wave h-24 rounded-2xl" />)}</div>
            ) : filtered.length === 0 ? (
                <div className="card-premium p-10 text-center">
                    <Car className="h-8 w-8 mx-auto mb-3 text-zinc-200" />
                    <p className="text-zinc-400 text-sm">No listings yet</p>
                    {user && <Button size="sm" variant="outline" className="rounded-xl mt-3" onClick={() => setPostDialog(true)}>Post First Listing</Button>}
                </div>
            ) : (
                <div className="space-y-3">
                    {filtered.slice(0, 5).map(ride => {
                        const cfg = TYPE_CONFIG[ride.type] || TYPE_CONFIG.carpool;
                        const Icon = cfg.icon;
                        const seatsLeft = (ride.seats_available || 0) - (ride.seats_taken || 0);
                        const isFull = seatsLeft <= 0;
                        return (
                            <div key={ride.id} className={`rounded-2xl p-4 border border-zinc-100 dark:border-zinc-800 ${cfg.light} hover:shadow-premium transition-all`}>
                                <div className="flex items-center justify-between gap-4">
                                    <div className="flex items-center gap-3 flex-1 min-w-0">
                                        <div className={`h-9 w-9 rounded-xl flex items-center justify-center shrink-0 ${cfg.color}`}>
                                            <Icon className="h-4 w-4" />
                                        </div>
                                        <div className="min-w-0">
                                            <p className="font-semibold text-sm text-zinc-900 dark:text-zinc-100">{ride.driver_name || ride.driver_email?.split('@')[0]}</p>
                                            <div className="flex items-center gap-3 text-xs text-zinc-500 mt-0.5 flex-wrap">
                                                <span className="flex items-center gap-1"><MapPin className="h-3 w-3" />{ride.from_location} → {ride.to_location}</span>
