/**
 * usePlatform — React hook that bootstraps the ServiceFlow platform layer.
 * 
 * Call this once at app root. It:
 *   1. Starts the automation engine (loads rules, subscribes to events)
 *   2. Seeds default automation rules if none exist
 *   3. Returns platform state (notification count, etc.)
 * 
 * Usage:
 *   const { unreadNotifications } = usePlatform(user);
 */

import { useEffect, useState } from 'react';
import { automationEngine } from '@/lib/platform/automationEngine';

export function usePlatform(user) {
    const [unreadNotifications, setUnreadNotifications] = useState(0);
    const [platformReady, setPlatformReady] = useState(false);

    useEffect(() => {
        if (!user?.email) return;

        const init = async () => {
            // Start the automation engine
            await automationEngine.start();
            await automationEngine.seedDefaultRules();
            setPlatformReady(true);
        };

        init().catch(e => console.warn('[Platform] Init warning:', e));
    }, [user?.email]);

    // Track unread notifications in real-time
    useEffect(() => {
        if (!user?.email) return;

        // Initial count
            .then(n => setUnreadNotifications(n.length))
            .catch(() => { });

        // Subscribe to new notifications
            if (event.type === 'create' && event.data.recipient_email === user.email && !event.data.is_read) {
                setUnreadNotifications(c => c + 1);
            }
            if (event.type === 'update' && event.data.recipient_email === user.email) {
                // Re-fetch count on any update
                    .then(n => setUnreadNotifications(n.length))
                    .catch(() => { });
            }
        });

        return () => unsub();
    }, [user?.email]);

    return { unreadNotifications, platformReady };
}

/**
 * ServiceFlow Audit Logger
 * 
 * Every significant action in the platform is recorded here.
 * Provides a full, immutable trail of what happened, who did it, and when.
 * 
 * Usage:
 *   import { auditLogger } from '@/lib/platform/auditLogger';
 *   await auditLogger.log({ actor, action, resourceType, resourceId, prevState, newState });
 */

import { generateCorrelationId } from './utils';

class AuditLogger {
    constructor() {
        this._queue = [];
        this._flushing = false;
        this._sessionId = generateCorrelationId();
    }

    /**
     * Log an audit event. Non-blocking — queues and flushes asynchronously.
     */
    log({
        actor = 'system',
        actorRole = 'system',
        action,
        resourceType,
        resourceId = null,
        previousState = null,
        newState = null,
        metadata = {},
        severity = 'info',
        tags = [],
        correlationId = null,
    }) {
        this._queue.push({
            actor_email: actor,
            actor_role: actorRole,
            action,
            resource_type: resourceType,
            resource_id: resourceId,
            previous_state: previousState,
            new_state: newState,
            metadata,
            session_id: this._sessionId,
            correlation_id: correlationId || this._sessionId,
            severity,
            tags,
        });

        this._scheduleFlush();
    }

    _scheduleFlush() {
        if (this._flushing) return;
        this._flushing = true;
        setTimeout(() => this._flush(), 500); // batch writes
    }

    async _flush() {
        if (this._queue.length === 0) { this._flushing = false; return; }
        const batch = this._queue.splice(0, 10); // process up to 10 at once
        try {
        } catch (e) {
            console.warn('[AuditLogger] Flush error (non-critical):', e);
        }
        this._flushing = false;
        if (this._queue.length > 0) this._scheduleFlush();
    }

    // Convenience methods
    logBookingAction({ actor, actorRole, action, booking, previousState }) {
        this.log({
            actor, actorRole, action,
            resourceType: 'Booking',
            resourceId: booking?.id,
            previousState,
            newState: booking,
            tags: ['booking', booking?.status],
        });
    }

    logProviderAction({ actor, actorRole, action, provider, previousState }) {
        this.log({
            actor, actorRole, action,
            resourceType: 'Provider',
            resourceId: provider?.id,
            previousState,
            newState: provider,
            tags: ['provider'],
        });
    }

    logSystemEvent({ action, resourceType, resourceId, metadata, severity = 'info' }) {
        this.log({ actor: 'system@serviceflow.app', actorRole: 'system', action, resourceType, resourceId, metadata, severity });
    }
}

